```jac
def sq(n: int) -> int { return n * n; }

def launch(n: int) -> object {
    return flow sq(n);   # `n` is a fresh binding per call -- pinned
}

with entry {
    futs = [launch(i) for i in range(5)];
    print([wait f for f in futs]);   # [0, 1, 4, 9, 16]
}
```

